import React, { useState } from 'react';
import './App.css';

function App() {
    const [objects, setObjects] = useState([]);
    const [draggingId, setDraggingId] = useState(null);

    function newObject() {
        setObjects([...objects, { id: Date.now(), left: 0, top: 0 }]);
    }

    function mouseDownOnObject(id) {
        setDraggingId(id)
    }

    function objectDragging(e) {
        setObjects(
            objects.map((obj) => {
                if (obj.dragging) {
                    return { ...obj, left: e.clientX, top: e.clientY };
                }
                return obj;
            }),
        );
    }
// return { ...obj, left: e.clientX, top: e.clientY };
    return (
        <div className="app-container">
            <header className="header">
                <h1>🎵 Sound Landscape</h1>
            </header>
            <div className="main">
                <aside className="sidebar">
                    <button onClick={newObject}>Добавить объект</button>
                </aside>
                <div
                    className="canvas-container"
                    onMouseMove={(e) => objectDragging(e)}
                    style={{
                        position: 'relative',
                    }}
                >
                    {objects.map((obj) => (
                        <div
                            onMouseDown={(e) => mouseDownOnObject(e, obj.id)}
                            className="obj"
                            key={obj.id}
                            style={{
                                position: 'absolute',
                                left: obj.left,
                                top: obj.top,
                            }}
                        ></div>
                    ))}
                </div>
            </div>
        </div>
    );
}

export default App;
